  const requestToken = async () => {
    const redirectUrl = AuthSession.getRedirectUrl();

    const authUrl = `${authorizationEndpoint}?client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUrl)}&response_type=code`;

    const response = await AuthSession.startAsync({ authUrl });
    
    if (response.type === 'success' && response.params.code) {
      try {
        const tokenResponse = await fetch(tokenEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: `grant_type=authorization_code&code=${response.params.code}&redirect_uri=${redirectUri}&client_id=${clientId}&client_secret=${clientSecret}`,
        });
        
        const tokenData = await tokenResponse.json();
        
        setAccessToken(tokenData.access_token);
      } catch (error) {
        Alert.alert('Error', 'Failed to exchange authorization code for access token');
      }
    } else {
      Alert.alert('Error', 'Failed to authenticate');
    }
  };

